import{_ as r,o as t,c as n,j as e,a as s,a1 as p}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"吾好梦中跑团","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/杂项/吾好梦中跑团.md","filePath":"4.资源分区/6.技艺及称号/杂项/吾好梦中跑团.md"}'),o={name:"4.资源分区/6.技艺及称号/杂项/吾好梦中跑团.md"};function d(_,a,l,i,c,b){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"吾好梦中跑团",tabindex:"-1"},[s("吾好梦中跑团 "),e("a",{class:"header-anchor",href:"#吾好梦中跑团","aria-label":'Permalink to "吾好梦中跑团"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"灵魂蓝调013")])])],-1),p('<h1 id="吾好梦中跑团-1" tabindex="-1">吾好梦中跑团 <a class="header-anchor" href="#吾好梦中跑团-1" aria-label="Permalink to &quot;吾好梦中跑团&quot;">​</a></h1><p>吾好梦中跑团</p><p>本质：特异<br> 价格：1000<br> “好忙啊，都没时间开团了，要是能在梦里开团就好了”<br> 灵感来源于某次充满白日梦的闲聊</p><p>兑换这个技艺后，人物可以通过接触将一个具有基础智能的生物标记为玩家，当你与该生物都陷入睡眠时，你可以对被标记的生物发出邀请，进行一场梦中跑团，当然的，被标记的生物有权拒绝你的邀请。</p><p>在你进入一种类似清醒梦的状态，可以自由的在梦中搭建场景，设定规则，扮演npc，而梦境内场景的细致和拟真程度和你的智力相关，每花费一分钟变可以进行一次单纯的智力鉴定，得到的成功数可以通过多次鉴定叠加，当成功数为10时，你在梦境中搭建的世界在感官上与真实世界无异，但这仅仅是跑团额场景罢了，并非你真正的创造了一个世界。</p><p>随后只要你与你所标记的生物在同一个世界，且你与对方都陷入沉睡，你便可以对他发出跑团邀请，参与你主持的游戏。显然的，这一能力除了本身的娱乐用法外，还可以当做一超远程的联络手段使用。<br> 人物一次所能拉入自身梦境的玩家数为自身的决心属性<br> 考虑到可能一晚无法结团，梦境自带存档读档功能。</p><p>选开：<br> 真实的跑团奖励<br> 前提：拥有吾好梦中跑团<br> 价格：1000分<br> 每影片/年一次，当你在梦境中结束一段冒险后，可以为你的玩家发放总价格不超过250分的奖励，这一奖励将真实的反映在玩家身上，你可以从规则书内寻找总价不超过250分的道具能力发放，也可以通过撰写规则，为你的玩家发放更加合适你们所经历的冒险背景的道具，但总价格依然不因超过250分。<br> （注：考虑到你在团中带团，所以使用后者时，应询问你的游戏主持人，允不允许自由撰写）</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',9)])])}const m=r(o,[["render",d]]);export{f as __pageData,m as default};
